SELECT classifier, class, accuracy
FROM classification_results
ORDER BY accuracy DESC;

SELECT classifier, MAX(f1_score) AS max_f1_score
FROM classification_results
WHERE classifier = 'example_classifier';

SELECT classifier, accuracy
FROM classification_results
ORDER BY accuracy DESC;

SELECT result_id, ts_id, project_id, model_id, classifier, class, accuracy, precision, recall, f1_score
FROM classification_results
ORDER BY accuracy DESC;
